#include <stdio.h>
#include <stdint.h>

uint32_t reverseBits(uint32_t x) {
    uint32_t rev = 0;
    for (int i = 0; i < 32; ++i) {
        rev = (rev << 1) | (x & 1U);
        x >>= 1;
    }
    return rev;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint32_t x;
        scanf("%u", &x);
        printf("%u\n", reverseBits(x));
    }
    return 0;
}

